export const PAGES: LandingPage[] = [{ "slug": "comite-direction", "type": "equipe", "meta": { "title": "La plateforme de gouvernance projet pour que votre CODIR prenne 4X plus rapidement les bonnes décisions", "description": "AirSaas est la solution qui accompagne les comités de direction dans un pilotage de tous les projets stratégiques et programmes de transformation de l'entreprise." }, "sections": [{ "type": "hero", "title": "La plateforme de gouvernance projet pour que votre CODIR prenne ", "titleHighlight": "4X plus rapidement les bonnes décisions", "body": "<p>AirSaas est la solution <strong>qui accompagne les comités de direction</strong> dans un pilotage de tous les projets stratégiques et programmes de transformation de l'entreprise.</p>", "primaryCta": { "href": "/fr/meetings-pages", "label": "Réservez une démo" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Portfolio integrated" }, { "type": "testimonials", "title": "Ils parlent de nous", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp" }] }, { "type": "intro", "title": "L'outil-clé pour piloter avec flexibilité et clarté vos projets internes de la stratégie à l'exécution", "body": "<p>Sans transparence, il ne peut y avoir d'engagement. Avec AirSaas, entamez un profond changement dans la culture de votre entreprise, et accompagnez mieux vos équipes en collaborant autour de vos projets de manière efficace et transparente.</p>" }, { "type": "stats", "title": "Les chiffres qui vous feront adopter AirSaas", "items": [{ "value": "56%", "label": "Le pourcentage de projets qui échouent (sans AirSaas !) à cause du retard pris sur les décisions cruciales" }, { "value": "3 min", "label": "Le temps qu'il vous faudra pour prendre en main votre plateforme de gouvernance" }, { "value": "50", "label": "C'est le nombre de jours économisés par vos équipes à faire du powerpoint.. Moins de powerpoint à faire = Plus de temps pour faire des projets" }, { "value": "4x", "label": "C'est la rapidité à laquelle votre comité de direction prendra des décisions." }] }, { "type": "feature-split", "title": "Animez clairement et simplement vos comités de pilotage", "body": "<p>En quelques clics, AirSaas vous donne accès aux décisions et points d'attention de chacun de vos projets lors de vos comités de pilotage. Finie, la perte d'information : vous pilotez à la décision de manière claire et agile.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": false }, { "type": "feature-split", "title": "Une roadmap projet macro partagée", "body": "<p>Votre roadmap collaborative AirSaas vous permet de prioriser les décisions à prendre, grâce à des vues filtrées par programme, objectifs d'entreprise et équipes. Plus de visibilité, pour mieux piloter : c'est la promesse de la plateforme.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline", "reversed": true }, { "type": "feature-split", "title": "Uniformisez les reportings projets", "body": "<p>Générez en un clic dans votre plateforme des reportings projets homogènes, qui vous aident à prendre des décisions plus rapidement lors de vos réunions. Finies les présentations PowerPoint hétérogènes, trop détaillées, reçues à la va-vite la veille du comité de direction !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report ppt", "reversed": false }, { "type": "feature-split", "title": "Obtenez la bonne information, au bon moment", "body": "<p>En 5 minutes par semaine et par projet, les chefs de projets font remonter les informations cruciales pour le suivi de vos projets de transformation : jalons, décisions à prendre, points d'attention. Évitez les réunions \"informationnelles\" et les rushs de dernière minute pour faire votre reporting.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Pilotez vos projets de manière macro", "reversed": true }, { "type": "feature-split", "title": "Suivez l'avancée de vos programmes", "body": "<p>Toutes les données de vos projets sont consolidées sur vos pages programmes, pour en suivre l'avancée et les principaux indicateurs, le tout en temps réel.</p>", "reversed": false }, { "type": "cta", "title": "Rendez vos comités de direction plus efficaces et moins chronophages", "body": "<p>Adoptez dès maintenant une solution efficace de reporting pour vos comités de direction, qui offre de la visibilité à toutes les parties prenantes, et fait avancer la transformation de votre entreprise plus vite, plus simplement.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "feature-split", "title": "Vos équipes vont adorer nos intégrations natives", "body": "<p>Avec AirSaas aucune re-saisie d'information. Synchronisez vos outils de gestion de projet et profitez d'une vue macro des informations cruciales dont vous avez besoin sur AirSaas.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d484f5bef7b761e48fea37_Automation%20-%20integrations.webp", "imageAlt": "Automation - integrations", "reversed": false }] }, { "slug": "direction-de-la-transformation", "type": "equipe", "meta": { "title": "Direction de la transformation | AirSaas", "description": "Découvrez la solution qui accompagne les directions de la transformation à piloter l'ensemble des projets de l'entreprise en collaboration avec les métiers et l'IT. Avec AirSaas, positionnez vous au centre de cette transformation." }, "sections": [{ "type": "hero", "title": "L'outil des Directions de la transformation pour mieux piloter", "titleSuffix": "leurs grands programmes", "body": "<p>Découvrez la solution qui accompagne les directions de la transformation à piloter l'ensemble des projets de l'entreprise en collaboration avec les métiers et l'IT. Avec AirSaas, positionnez vous au centre de cette transformation.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Portfolio integrated" }, { "type": "testimonials", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia Marion Jaffré Mélinda SCHLEDER Maryline Breton Thomas Kerbiriou .Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/?utm_source=share&utm_medium=member_desktop" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)" }] }, { "type": "intro", "title": "La direction de la transformation au centre du changement culturel de l'entreprise", "body": "<p>Parce que la transformation de l'entreprise nécessite un profond changement dans sa culture, le directeur de la transformation digitale doit intégrer à sa mission cet accompagnement. Sans transparence, il ne peut y avoir d'engagement.<br/>La solution collaborative AirSaas permet aux équipes de comprendre et collaborer autour des projets de transformation de manière simple et compréhensible par tous.</p>" }, { "type": "stats", "title": "Pourquoi adopter AirSaas", "items": [{ "value": "3 min", "label": "C'est le temps qu'il vous faudra pour prendre en main l'outil" }, { "value": "100%", "label": "de visibilité sur l'état de santé des projets" }, { "value": "1 jour", "label": "Temps économisé par projet par mois à faire votre reporting manuel" }, { "value": "Merci", "label": "C'est ce que vous dira le CoDir après avoir mis en place AirSaas !" }] }, { "type": "feature-split", "title": "Animez clairement et simplement le comité de pilotage", "body": "<p>Pilotez par la décision : Pendant votre comité de pilotage vous aurez accès à toutes les décisions à prendre et historiques clés. Vous ne serez plus pris de court parce que vous n'avez pas la bonne information.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": false }, { "type": "feature-split", "title": "Pilotez les projets de manière macro", "body": "<p>Priorisez en continu et soyez agile grâce votre roadmap collaborative.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline", "reversed": true }, { "type": "feature-split", "title": "Uniformisez le reporting projet", "body": "<p>Générez votre flash report en un clic et envoyez le de manière régulière aux sponsors métiers. Ils ne pourront plus dire \"je ne savais pas !\"</p>", "reversed": false }, { "type": "feature-split", "title": "Faites gagner 1 jour par semaine à vos chefs de projet", "body": "<p>En 5 minutes par semaine et par projet, les chefs de projets font remonter les informations cruciales pour le suivi de projet : Jalon, décision à prendre, point d'attention.<br/>Evitez les réunions \"informationnelles\" et les rush de dernière minute pour faire un reporting.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d6fd5da1f291f6011dee8d_Portfolio%20share%20decision.webp", "imageAlt": "Portfolio share decision", "reversed": true }, { "type": "feature-stacked", "title": "Améliorer en continu votre manière de faire des projets", "body": "<p>Générez en un clic le bilan d'un projet contenant les métriques (délai, coût, engagement, etc.) mais aussi les retours \"DAKI\" de l'équipe projet. Parfait pour s'améliorer ensemble.</p>", "subSections": [{ "title": "DROP", "body": "<p>Ce que vous souhaitez arrêter.</p><blockquote>Exemple : Démarrer un projet sans avoir nommé de sponsor.</blockquote>" }, { "title": "ADD", "body": "<p>Ce que vous aimeriez essayer.</p><blockquote>Exemple : Ajouter un utilisateur final à chaque review.</blockquote>" }, { "title": "KEEP", "body": "<p>Ce qu'il faut garder.</p><blockquote>Exemple : Le point d'avancement bi-mensuel avec le flash report.</blockquote>" }, { "title": "IMPROVE", "body": "<p>Ce que vous souhaitez améliorer.</p><blockquote>Exemple : Améliorer la précision des maquettes pour couvrir tous les effets de bord.</blockquote>" }] }, { "type": "cta", "title": "Choisissez de gagner du temps et du contrôle", "body": "<p>Adoptez dès maintenant une solution efficace de reporting projet.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "feature-split", "title": "AirSaas s'intégre à vos outils", "body": "<p>Synchronisez vos outils de gestions de projets et profitez d'une vue macro sur AirSaas.<br/>Connectez votre MS Teams et tenez informés vos collaborateurs.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d48497b08e93531f3ba49b_Graphic%20Integrations.webp", "imageAlt": "Automation - integrations", "reversed": false }] }, { "slug": "it-et-operation", "type": "equipe", "meta": { "title": "L'outil de gestion de gouvernance conçu pour vos projets IT - Métier | AirSaas", "description": "AirSaas accompagne les DSI dans le pilotage de leur portfolio de projets IT en collaboration avec les métiers. Embarquez toute l'entreprise dans sa transformation, fluidifiez la prise de décision, et devenez un véritable partenaire business." }, "sections": [{ "type": "hero", "title": "L'outil de gestion de gouvernance conçu pour vos projets IT - Métier", "body": "<p>AirSaas accompagne les DSI dans le pilotage de leur portfolio de projets IT en collaboration avec les métiers. Embarquez toute l'entreprise dans sa transformation, fluidifiez la prise de décision, et devenez un véritable partenaire business.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Portfolio integrated" }, { "type": "testimonials", "title": "Ils parlent de nous", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)&dashCommentUrn=urn:li:fsd_comment:(7123209071331020802,urn:li:activity:7122982646506278912)", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp" }] }, { "type": "intro", "title": "Et si vous étiez vraiment au centre de la transformation de votre entreprise ?", "body": "<p>Notre mission ? Faire de vous, DSI, le pivot de la transformation de l'entreprise en structurant la gouvernance de tous les projets, grâce à une plateforme unique, simple, et collaborative. La vôtre ? Faire passer votre entreprise à l'étape supérieure en gouvernance de projet !</p>" }, { "type": "stats", "title": "Les chiffres qui vous feront adopter AirSaas", "items": [{ "value": "56%", "label": "Le pourcentage de projets qui échouent (sans AirSaas !) à cause du retard pris sur les décisions cruciales" }, { "value": "3 min", "label": "Le temps qu'il vous faudra pour prendre en main votre plateforme de gouvernance" }, { "value": "1 jour", "label": "Le temps économisé en moyenne par projet et par mois par rapport à vos reportings manuels" }, { "value": "0€", "label": "Le prix d'un utilisateur non-contributeur d'AirSaas, pour donner la bonne visibilité à tous" }] }, { "type": "intro", "title": "La plateforme qui fluidifie votre gouvernance projet", "body": "<p>C'est parce que 90% des projets ont une composante IT qu'AirSaas a été pensé pour aligner l'IT, les métiers et la direction générale, autour d'une plateforme unique qui simplifie la collaboration.</p>" }, { "type": "feature-split", "title": "Centralisez l'information pour mieux piloter", "body": "<p>Grâce à une roadmap collaborative et des vues filtrées, vous visualisez aisément l'avancement des projets et les points d'attention. Plus besoin de vous éparpiller entre vos différents outils de gestion de projet !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline", "reversed": false }, { "type": "feature-split", "title": "Collaborez pour impliquer les métiers de A à Z", "body": "<p>Offrez à vos métiers une expérience collaborative de cadrage de projet, et permettez-leur de suivre aisément les décisions et points d'attention qui méritent leur engagement.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66865ccd6319bebdceb619e4_Presentation-review-slide.png", "imageAlt": "Flash report", "reversed": true }, { "type": "feature-split", "title": "Uniformisez votre reporting projet", "body": "<p>Générez votre flash report en un clic, sous un format lisible et homogène, et envoyez-le de manière régulière aux sponsors métiers. Ils ne pourront plus dire \"je ne savais pas !\"</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report ppt", "reversed": false }, { "type": "feature-split", "title": "Poussez vos chefs de projet vers l'excellence", "body": "<p>En 5 minutes par semaine par projet, les chefs de projets font remonter les informations cruciales pour le suivi : jalons, décisions à prendre, points d'attention. Évitez-leur les réunions \"informationnelles\" et les rush de dernière minute, et standardisez leur manière de mener leurs projets.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Project page", "reversed": true }, { "type": "feature-split", "title": "Animez clairement et simplement votre comité de pilotage", "body": "<p>Pendant votre comité de pilotage, visualisez toutes les décisions à prendre et historiques-clés de vos projets. Vous ne serez plus pris de court parce que vous n'avez pas la bonne information, et pourrez enfin piloter par la décision.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": false }, { "type": "cta-highlight", "title": "Gagnez en temps en en contrôle sur votre portefeuille projets", "body": "<p>Adoptez dès maintenant une solution moderne de gestion de gouvernance, et devenez un véritable pivot de la transformation de votre entreprise.</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" } }, { "type": "feature-split", "title": "La marketplate AirSaas : pour intégrer nativement la plateforme à vos outils", "body": "<p>Centralisez toutes vos informations cruciales (tickets, jalons…) depuis vos outils de gestion de tâches sur AirSaas, et diffusez-les via vos canaux de communication interne. Tout le monde est au diapason, et vous gouvernez de manière optimale.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d484f5bef7b761e48fea37_Automation%20-%20integrations.webp", "imageAlt": "Automation - integrations" }, { "type": "intro", "title": "Injectez de la méthodologie dans votre gestion de portefeuille", "body": "<p>C'est à partir des retours d'expérience de plus de 60 DSI qu'AirSaas a été conçu. En ressort une méthodologie simple et claire, qui vous permet de formaliser vos pratiques de gestion de projet et de structurer votre gouvernance. Et, pour vous aider à déployer les meilleures pratiques de gestion de portefeuille, nous avons fait de ces échanges avec des DSI un podcast : CIO Révolution.</p>", "primaryCta": { "label": "Ecoutez le podcast \"CIO Révolution\"", "href": "/fr/blog-3/cio-revolution" } }] }, { "slug": "outil-pmo", "type": "equipe", "meta": { "title": "L'outil PPM pour un PMO moderne | AirSaas", "description": "AirSaas c'est la solution la plus simple pour avoir une vue macro consolidée du portefeuille projet. Avec AirSaas vous n'aurez plus besoin de faire des PowerPoints et de courir après les chefs de projets pour avoir les informations clefs." }, "sections": [{ "type": "hero", "title": "L'outil PPM pour un PMO moderne", "body": "<p>AirSaas c'est la solution la plus simple pour avoir une vue macro consolidée du portefeuille projet. Avec AirSaas vous n'aurez plus besoin de faire des PowerPoints et de courir après les chefs de projets pour avoir les informations clefs. Et oui un PPM peut avoir une UX au top</p>", "primaryCta": { "label": "Réservez une démo", "href": "/fr/meetings-pages" }, "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3b2244fc905908e85593_Portfolio%20integrated.webp", "imageAlt": "Portfolio integrated" }, { "type": "testimonials", "title": "Témoignages clients", "testimonials": [{ "name": "Thomas Sagnimorte", "role": "DSI chez Millet Mountain Group", "text": "Super outil qui nous permet de fluidifier le pilotage de notre portefeuille projet. Je recommande!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154ad9e5406b2f6686f963_thomas-sagnimorte.webp", "linkedinUrl": "https://www.linkedin.com/posts/thomas-sagnimorte-593b2b1_cest-tellement-agr%C3%A9able-de-co-construire-activity-7084118266675101697-6OuH/" }, { "name": "Marie-Odile Lhomme", "role": "Chief Digital & Information Officer", "text": "Un beau projet et une vraie dynamique d'équipe transverse DSI et Métiers au service du management du portefeuille de projets Audencia. Un beau partenariat AirSaas Bertran Ruiz! Heureuse de constater au jour le jour la progression ... et les premiers résultats! On continue!", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154d91a69420f9a97694fe_marie-odile-lhomme.webp", "linkedinUrl": "https://www.linkedin.com/posts/molhomme_mon-top-workshop-de-la-semaine-%C3%A9tait-avec-activity-7080456869751713792-NQT9/" }, { "name": "Clement Royer", "role": "DSI - ICT MANAGER chez Chiesi France", "text": "Avec l'outil AirSaas nous avons pu ritualiser nos réunions de revu projet en supprimant les PowerPoints et les réunions peu efficaces. Cela nous permet d'avoir toute la DSI alignée et informée sur l'ensemble des projets au quotidien. Un outil vraiment TOP !", "avatarSrc": "https://cdn.prod.website-files.com/609552290d93fdcbbc0f084b/66154db4a1cc5e0256fc6539_clement-royer.webp", "linkedinUrl": "https://www.linkedin.com/feed/update/urn:li:activity:7122982646506278912/?commentUrn=urn:li:comment:(activity:7122982646506278912,7123209071331020802)" }] }, { "type": "stats", "title": "Les chiffres qui vous feront adopter AirSaas", "items": [{ "value": "80%", "label": "C'est la réduction moyenne du nombre de réunions projets constatée après 4 mois d'utilisation d'Airsaas. Pourquoi faire un meeting quand l'information est claire, centralisée et accessible à tous ?" }, { "value": "100%", "label": "C'est le taux de réduction du nombre de projet lancé sans capacité à faire ou sans objectif clair." }, { "value": "30K€", "label": "C'est le montant annuel moyen que vous dépensez en temps-homme pour faire du PowerPoint projet (si vous avez plus de 20 projets)." }] }, { "type": "intro", "title": "Une plateforme de gouvernance projet à la hauteur de vos ambitions", "body": "<p>Notre mission ? Vous permettre de devenir le pivot de la transformation de l'entreprise en structurant la gouvernance de tous les projets, grâce à une plateforme simple que le top management va adorer. La vôtre ? Faire passer votre entreprise à l'étape supérieure en gouvernance de projet !</p>" }, { "type": "feature-split", "title": "Partagez simplement les roadmaps à toute l'organisation", "body": "<p>Une roadmap, ça bouge, ça vit, c'est un élément clé pour aligner le top management en continu. Avec AirSaas, plus besoin de faire des PowerPoints à rallonge : l'information est centralisée, partageable et sympa à visualiser (parce que quand c'est beau, c'est quand même plus impactant).</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65ce3c00c0a4886fc8e9f671_Portfolio%20project%20timeline%20view.webp", "imageAlt": "Portfolio timeline" }, { "type": "feature-split", "title": "Un capacity planning par équipe simple et actionnable", "body": "<p>Visualisez en un clin d'oeil si vous êtes dans les clous... ou dans les choux. Grâce à cette vue vous avez les bases d'une discussion pragmatique pour prendre les décisions :</p><ul><li>Peut-on faire plus de projets ? Faut-il en enlever ?</li><li>Quels sont les jalons qui nous plombent ? Peut-on les découper ?</li><li>Doit-on recruter ou mettre l'équipe en tension ? Pendant combien de temps ?</li></ul>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66334ee7bcfcb0aa45802537_Capacity%20screen.webp", "imageAlt": "Capacity Marketing" }, { "type": "feature-split", "title": "Chaque directeur définit ses prios", "body": "<p>Demandez aux directeurs de prioriser parmi les projets dont son équipe est à l'origine. Deux projets ne peuvent pas avoir la même priorité. Une fois prêts, ils valident leur choix. C'est simple, transparent et puissant.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/663d07a346b12e77e37ddd72_Prioritization%20per%20team%20ppt%20d%26d.webp", "imageAlt": "Priorisation options" }, { "type": "feature-split", "title": "Diffusez un cadrage projet standardisé", "body": "<p>Remplissez les fiches cadrage de projet de manière collaborative, et guidez vos collaborateurs vers un véritable niveau d'excellence en gestion de projet. A vous une culture projet homogénéisée !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35d6a6c51a9712103f44c_Presentation-scope-slide.webp", "imageAlt": "Presentation scope", "reversed": true }, { "type": "feature-split", "title": "Une newsletter sponsor que votre direction va adorer", "body": "<p><strong>Tendance des projets vitaux</strong><br/>Un récapitulatif de la santé des projets vitaux de votre organisation pour leur permettre de \"sentir\" la tendance du moment.</p><p><strong>Tendance de leurs projets à eux</strong><br/>Un aperçu de leurs projets, ceux en amélioration et ceux en dégradation qui nécessitent leur attention. En un clic, ils peuvent accéder à la fiche projet.</p><p><strong>Projets en retard d'actualisation</strong><br/>Un rappel des projets qui méritent d'être mis à jour. Si cette section est vide, vous êtes tranquile !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/66543b6b307a64952dc9c936_Control%20tower%20email%20FR-1.png", "imageAlt": "Bilan de santé", "reversed": true }, { "type": "feature-split", "title": "Votre reporting projet en un clic", "body": "<p>Générez votre <strong>reporting flash en un seul clic</strong>, et homogénéisez vos présentations, pour faciliter la prise de décision. Autant de temps gagné pour vous focaliser sur le coaching de vos chefs de projet et votre gouvernance.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35ce9e34fd87ad7612c9d_Flash%20report%20ppt.webp", "imageAlt": "Flash report ppt" }, { "type": "feature-split", "title": "Fluidifiez votre prise de décisions importantes et urgentes", "body": "<p><strong>Centralisez vos décisions</strong> sous forme de Kanban, et partagez-les aisément avec toutes les parties prenantes de vos projets. Finies les informations perdues dans vos mails ou flux de discussions instantanées !</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": true }, { "type": "feature-split", "title": "Impliquez simplement les chefs de projet", "body": "<p>En 5 minutes par semaine par projet, les chefs de projets remontent les informations cruciales pour le suivi : Jalon, décision à prendre, point d'attention.<br/>Evitez les réunions \"informationnelles\" et les rush de dernière minute pour faire un reporting.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d5a7778369803dea86381b_Project%20page.webp", "imageAlt": "Project page" }, { "type": "feature-split", "title": "Animez clairement et simplement vos CoPil", "body": "<p>Pilotez par la décision : Pendant votre comité de pilotage vous aurez accès à toutes les décisions à prendre et historiques clés. Vous ne serez plus pris de court parce que vous n'avez pas la bonne information.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d35c96ec9fbf11d78e4b44_Portfolio%20decisions%20(show%20projects%20title).webp", "imageAlt": "Portfolio decisions", "reversed": true }, { "type": "cta", "title": "Et si vous repreniez le contrôle de votre portefeuille de projets ?", "body": "<p>Adoptez dès maintenant une solution de gestion de gouvernance moderne, qui fait gagner vos projets en temps et en efficacité.</p>", "ctaLabel": "Réservez une démo", "ctaHref": "/fr/meetings-pages" }, { "type": "feature-split", "title": "Grâce à sa marketplace AirSaas s'intègre nativement à vos outils du quotidien", "body": "<p>Centralisez toutes vos informations cruciales (tickets, jalons…) depuis vos outils de gestion de tâches sur AirSaas, et diffusez-les via vos canaux de communication interne. Tout le monde est au diapason, et vous gouvernez de manière optimale.</p>", "imageSrc": "https://cdn.prod.website-files.com/609552290d93fd43ba0f0849/65d484f5bef7b761e48fea37_Automation%20-%20integrations.webp", "imageAlt": "Automation - integrations" }] }] as const;

export const PAGES_BY_SLUG: Record<string, LandingPage> =
  Object.fromEntries(PAGES.map((p) => [p.slug, p]));
